import React, { useEffect } from "react";
import { BrowserRouter as Router, Redirect, Switch } from "react-router-dom";
import "./App.css";
import ProtectedRoute from "./components/protected-route";
import { useRecoilValue, useSetRecoilState } from "recoil";
import { IsLoggedIn, CurrentUser } from "./modules/global/global-states";
import MenuBar from "./components/menu-bar";
import { Auth } from "./api";
import NotificationBox from "./components/notification-box";
// PAGE IMPORT
// PAGE IMPORT - HOME PAGE / DASHBOARD PAGE IMPORT
import DashboardPage from "./components/dashboard-page/dashboard-page";
// PAGE IMPORT - EQUIPMENT HEALTH PAGE IMPORT
import EquipmentHealthPage from "./components/equipment-health-page";
// PAGE IMPORT - DEMAND FORECAST PAGE IMPORT
import DemandForecastingPage from "./components/demand-forecasting-page";
// PAGE IMPORT - SMART TROUBLESHOOTING PAGE IMPORT
import SmartTroubleShootingPage from "./components/smart-troubleshooting-page";
import AISmartTroubleShootingPage from "./components/smart-troubleshooting-page/components/AISmartTroubleshooting";
import CorrectiveMaintenancePage from "./components/smart-troubleshooting-page/components/AISmartTroubleshooting/components/corrective-maintenance-page/corrective-maintenance-page";
import PreventiveMaintenancePage from "./components/smart-troubleshooting-page/components/AISmartTroubleshooting/components/preventive-maintenance-page/preventive-maintenance-page";

// PAGE IMPORT - ADMIN PANEL PAGE IMPORT
import AdminPanelPage from "./components/admin-panel-page";
import VideoLogsPage from "components/admin-panel-page/components/video-logs";
import ErrorLogsPage from "components/admin-panel-page/components/error-logs";
import EquipmentInfoRecordPage from "components/admin-panel-page/components/equipment-info-record";
import EquipmentHealthRecordHistoryPage from "components/admin-panel-page/components/equipment-health-record-history";
import ActivityLogsPage from "components/admin-panel-page/components/activity-logs";
import SparePartsStockPage from "components/admin-panel-page/components/spare-parts-stock";
import RecommendationApprovalPage from "components/admin-panel-page/components/recommendation-approval";
import RecommendationPanelPage from "components/admin-panel-page/components/recommendation-panel";

function App() {
  const isLoggedIn = useRecoilValue(IsLoggedIn);
  useLoggedinState();
  return (
    <div className="App">
      <NotificationBox />
      <Router>
        {isLoggedIn && <MenuBar />}
        <Switch>
          {/* HOME PAGE / DASHBOARD PAGE */}
          <ProtectedRoute path="/" exact>
            <DashboardPage />
          </ProtectedRoute>

          {/* EQUIPMENT HEALTH PAGE */}
          <ProtectedRoute path="/equipment-health" exact>
            <EquipmentHealthPage />
          </ProtectedRoute>

          {/* DEMAND FORECASTING PAGE */}
          <ProtectedRoute path="/demand-forecasting" exact>
            <DemandForecastingPage />
          </ProtectedRoute>

          {/* SMART TROUBLESHOOTING PAGE */}
          <ProtectedRoute path="/smart-troubleshooting" exact>
            <SmartTroubleShootingPage />
          </ProtectedRoute>
          <ProtectedRoute
            path="/smart-troubleshooting/ai-smart-troubleshooting"
            exact
          >
            <AISmartTroubleShootingPage />
          </ProtectedRoute>
          <ProtectedRoute
            path="/smart-troubleshooting/ai-smart-troubleshooting/corrective-maintenance-page"
            exact
          >
            <CorrectiveMaintenancePage />
          </ProtectedRoute>
          <ProtectedRoute
            path="/smart-troubleshooting/ai-smart-troubleshooting/preventive-maintenance-page"
            exact
          >
            <PreventiveMaintenancePage />
          </ProtectedRoute>
          <ProtectedRoute path="/smart-troubleshooting/error-log-capture" exact>
            {/* <ErrorLogCapturePage /> */}
          </ProtectedRoute>
          <ProtectedRoute path="/smart-troubleshooting/smart-om-manual" exact>
            {/* <SmartOMManualPage /> */}
          </ProtectedRoute>
          <ProtectedRoute
            path="/smart-troubleshooting/search-equipment-historical-record"
            exact
          >
            {/* <SearchEquipmentHistoricalRecordPage /> */}
          </ProtectedRoute>

          {/* ADMIN PANEL PAGE */}
          <ProtectedRoute path="/admin-panel" exact>
            <AdminPanelPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/video-logs" exact>
            <VideoLogsPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/error-logs" exact>
            <ErrorLogsPage />
          </ProtectedRoute>
          <ProtectedRoute
            path="/admin-panel/equipment-info-record-database"
            exact
          >
            <EquipmentInfoRecordPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/activity-logs" exact>
            <ActivityLogsPage />
          </ProtectedRoute>
          <ProtectedRoute
            path="/admin-panel/equipment-health-record-history-database"
            exact
          >
            <EquipmentHealthRecordHistoryPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/spare-parts-stock-database" exact>
            <SparePartsStockPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/recommendation-approval-cm" exact>
            <RecommendationApprovalPage />
          </ProtectedRoute>
          <ProtectedRoute path="/admin-panel/recommendation-panel-pm" exact>
            <RecommendationPanelPage />
          </ProtectedRoute>
          <Redirect to="/" />
        </Switch>
      </Router>
    </div>
  );
}

function useLoggedinState() {
  const setIsLoggedIn = useSetRecoilState(IsLoggedIn);
  const setCurrentUser = useSetRecoilState(CurrentUser);
  useEffect(() => {
    const json = localStorage.getItem("emsd");
    if (json && json !== "") {
      const emsdInfo = JSON.parse(json);
      setIsLoggedIn(true);
      setCurrentUser({
        username: emsdInfo.username,
        isAdmin: emsdInfo.isAdmin,
        accessToken: emsdInfo.accessToken,
      });
      Auth.signIn(emsdInfo.accessToken);
    }
  }, [setCurrentUser, setIsLoggedIn]);
}

export default App;
